def gen(rng, size):
    n = size
    counts = {}
    nums = []
    freqs = []
    for _ in range(n):
        nid = rng.randint(1, 100)
        current = counts.get(nid, 0)
        # choose freq that won't make count negative
        max_remove = current
        if max_remove == 0:
            f = rng.randint(1, 10)
        else:
            f = rng.randint(-max_remove, 10)
        if f == 0:
            f = 1
        counts[nid] = current + f
        nums.append(nid)
        freqs.append(f)
    return [nums, freqs]

