class Solution:
    def mostFrequentIDs(self, nums, freq):
        counts = {}
        ans = []
        for nid, f in zip(nums, freq):
            counts[nid] = counts.get(nid, 0) + f
        # recompute each step from scratch
        counts2 = {}
        for nid, f in zip(nums, freq):
            counts2[nid] = counts2.get(nid, 0) + f
            ans.append(max(counts2.values()) if any(v > 0 for v in counts2.values()) else 0)
        return ans

