class Solution:
    def mostFrequentIDs(self, nums, freq):
        import heapq
        counts = {}
        heap = []  # max-heap stored as negatives
        ans = []
        for nid, f in zip(nums, freq):
            counts[nid] = counts.get(nid, 0) + f
            heapq.heappush(heap, (-counts[nid], nid))
            while heap and -heap[0][0] != counts.get(heap[0][1], 0):
                heapq.heappop(heap)
            ans.append(-heap[0][0] if heap else 0)
        return ans

