var mostFrequentIDs = function(nums, freq) {
    // Use a simple sorted approach for JS (no built-in max-heap)
    // O(n log n) with Map + sorted extraction
    const counts = new Map();
    const ans = [];
    // MinHeap implementation
    class MaxHeap {
        constructor() { this.h = []; }
        push(val) {
            this.h.push(val);
            this._bubbleUp(this.h.length - 1);
        }
        pop() {
            const top = this.h[0];
            const last = this.h.pop();
            if (this.h.length > 0) { this.h[0] = last; this._siftDown(0); }
            return top;
        }
        peek() { return this.h[0]; }
        size() { return this.h.length; }
        _bubbleUp(i) {
            while (i > 0) {
                const p = (i - 1) >> 1;
                if (this.h[p][0] >= this.h[i][0]) break;
                [this.h[p], this.h[i]] = [this.h[i], this.h[p]];
                i = p;
            }
        }
        _siftDown(i) {
            const n = this.h.length;
            while (true) {
                let largest = i;
                const l = 2*i+1, r = 2*i+2;
                if (l < n && this.h[l][0] > this.h[largest][0]) largest = l;
                if (r < n && this.h[r][0] > this.h[largest][0]) largest = r;
                if (largest === i) break;
                [this.h[largest], this.h[i]] = [this.h[i], this.h[largest]];
                i = largest;
            }
        }
    }
    const heap = new MaxHeap();
    for (let i = 0; i < nums.length; i++) {
        const nid = nums[i], f = freq[i];
        counts.set(nid, (counts.get(nid) || 0) + f);
        heap.push([counts.get(nid), nid]);
        while (heap.size() > 0 && heap.peek()[0] !== counts.get(heap.peek()[1])) {
            heap.pop();
        }
        ans.push(heap.size() > 0 ? heap.peek()[0] : 0);
    }
    return ans;
};
